SELECT MAX(volume) AS highest_volume, date
FROM trading_volume
WHERE stock_id = 0;

SELECT AVG(market_cap) AS average_market_cap
FROM stocks
WHERE sector = 'Energy' AND exchange = 'NYSE';

SELECT sector, AVG(market_cap) AS avg_market_cap
FROM stocks
GROUP BY sector;

SELECT *
FROM daily_prices
WHERE close_price > (
    SELECT AVG(close_price)
    FROM daily_prices
);

SELECT AVG(market_cap) AS AvgMarketCap
FROM stocks
WHERE sector = 'Technology';

SELECT tv.stock_id, AVG(tv.volume) AS average_volume
FROM trading_volume tv
GROUP BY tv.stock_id
HAVING AVG(tv.volume) > (
    SELECT AVG(volume) FROM trading_volume
);
